type ContextCode = {
  code: string;
  title: string;
  thesis: string;
  points: Array<{ title: string; text: string }>;
};

type Props = {
  card: ContextCode;
  imageSrc?: string;
  imageAlt?: string;
};

const ballScene = "data:image/webp;base64,";

export function ContextCodeCard({ card, imageSrc = ballScene, imageAlt = "Авторская иллюстрация дворянского бала в России 1840-х годов" }: Props) {
  return (
    <section className="context-code-card" aria-label={card.title}>
      <div className="context-code-image">
        <img src={imageSrc} alt={imageAlt} />
        <span>{card.code}</span>
      </div>
      <div className="context-code-copy">
        <p className="eyebrow">{card.code}</p>
        <h2>{card.title}</h2>
        <p className="context-code-thesis">{card.thesis}</p>
        <div className="context-code-points">
          {card.points.map((point) => (
            <article key={point.title}>
              <h3>{point.title}</h3>
              <p>{point.text}</p>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}
